					Status      string   `json:"status"`
					ChildRunIds []string `json:"childRunIds"`
				} `json:"node"`
				Cursor string `json:"cursor"`
			} `json:"edges"`
			TotalCount int `json:"totalCount"`
		} `json:"runs"`
	}
	if err := json.Unmarshal(resp["data"], &listOut); err != nil {
		t.Fatalf("parse list: %v", err)
